# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using UnityEngine.UI;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth;
    public int currency = 50;
    
    public Slider healthSlider; // Assign in inspector
    public Text currencyText;  // Assign in inspector

    void Start()
    {
        currentHealth = maxHealth;
        
        if(healthSlider != null)
            healthSlider.maxValue = maxHealth;

        UpdateUI();
    }
    
    public void TakeDamage(int damageAmount)
    {
        // Calculate the new health after taking damage
        currentHealth -= Mathf.Min(damageAmount, currentHealth);
        
        if (currentHealth <= 0)
            Die();
            
        UpdateUI();
    }
    
    public void AddCurrency(int amount)
    {
        currency += amount;
        UpdateUI();
    }

    // This is where you would implement purchasing items, etc.
    // For simplicity, this function just deducts cost from player's currency
    public bool TryBuyItem(int itemCost)
    {
        if (currency >= itemCost)
        {
            currency -= itemCost;
            UpdateUI();
            return true;
        }
        
        return false;
    }
    
    private void Die()
    {
        // Implement game over logic here
    }
    
    private void UpdateUI()
    {
        if (healthSlider != null)
            healthSlider.value = currentHealth;
            
        if (currencyText != null)
            currencyText.text = $"Currency: {currency}";
    }
}